require('dotenv').config();
const { Client, GatewayIntentBits, EmbedBuilder, ActionRowBuilder, ButtonBuilder, ButtonStyle, AttachmentBuilder } = require('discord.js');
const axios = require('axios');
const Anthropic = require('@anthropic-ai/sdk');
const { getVendorForBrand, getAllVendors } = require('./vendors');

const client = new Client({
  intents: [
      GatewayIntentBits.Guilds,
          GatewayIntentBits.GuildMessages,
              GatewayIntentBits.MessageContent,
                  GatewayIntentBits.GuildMessageReactions,
                    ],
                    });

                    const anthropic = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });
                    const BACKEND_URL = process.env.BACKEND_URL || 'https://semperfi-backend-production.up.railway.app';

                    // Store pending orders awaiting confirmation
                    const pendingOrders = new Map();

                    client.once('ready', () => {
                      console.log(`Semper Fi Discord Bot online as ${client.user.tag}`);
                      });

                      // Handle slash commands
                      client.on('interactionCreate', async (interaction) => {
                        if (!interaction.isChatInputCommand()) return;

                          if (interaction.commandName === 'order') {
                              const brand = interaction.options.getString('brand');
                                  const part = interaction.options.getString('part');
                                      const po = interaction.options.getString('po');
                                          const qty = interaction.options.getInteger('qty') || 1;
                                              const model = interaction.options.getString('model') || null;

                                                  const vendor = getVendorForBrand(brand);
                                                      if (!vendor) {
                                                            await interaction.reply({ content: `Unknown brand: **${brand}**. Cannot find a vendor. Please check the brand name.`, ephemeral: true });
                                                                  return;
                                                                      }

                                                                          const order = { brand, part, po, qty, model, vendor };
                                                                              await sendOrderConfirmation(interaction, order, true);
                                                                                }
                                                                                });

                                                                                // Handle button interactions (confirm/cancel)
                                                                                client.on('interactionCreate', async (interaction) => {
                                                                                  if (!interaction.isButton()) return;

                                                                                    const [action, orderId] = interaction.customId.split(':');
                                                                                      const order = pendingOrders.get(orderId);

                                                                                        if (!order) {
                                                                                            await interaction.reply({ content: 'This order has expired or already been processed.', ephemeral: true });
                                                                                                return;
                                                                                                  }

                                                                                                    pendingOrders.delete(orderId);
                                                                                                    
                                                                                                      if (action === 'confirm') {
                                                                                                          await interaction.update({ components: [] });
                                                                                                              await placeOrder(interaction, order);
                                                                                                                } else if (action === 'cancel') {
                                                                                                                    await interaction.update({
                                                                                                                          embeds: [buildEmbed(order, 'cancelled')],
                                                                                                                                components: [],
                                                                                                                                    });
                                                                                                                                      }
                                                                                                                                      });
                                                                                                                                      
                                                                                                                                      // Handle messages (natural text + photo)
                                                                                                                                      client.on('messageCreate', async (message) => {
                                                                                                                                        if (message.author.bot) return;
                                                                                                                                          // Only respond in channels named "orders" or "hvac-orders" or if mentioned
                                                                                                                                            const allowedChannels = ['orders', 'hvac-orders', 'parts-orders'];
                                                                                                                                              const inOrderChannel = allowedChannels.includes(message.channel.name);
                                                                                                                                                const mentioned = message.mentions.has(client.user);
                                                                                                                                                  if (!inOrderChannel && !mentioned) return;
                                                                                                                                                  
                                                                                                                                                    // Remove bot mention from text
                                                                                                                                                      let text = message.content.replace(`<@${client.user.id}>`, '').trim();
                                                                                                                                                      
                                                                                                                                                        // Check for image attachments
                                                                                                                                                          const imageAttachment = message.attachments.find(a =>
                                                                                                                                                              a.contentType && a.contentType.startsWith('image/')
                                                                                                                                                                );
                                                                                                                                                                
                                                                                                                                                                  if (imageAttachment) {
                                                                                                                                                                      await handlePhotoOrder(message, imageAttachment, text);
                                                                                                                                                                          return;
                                                                                                                                                                            }
                                                                                                                                                                            
                                                                                                                                                                              if (text.length > 5) {
                                                                                                                                                                                  await handleNaturalTextOrder(message, text);
                                                                                                                                                                                    }
                                                                                                                                                                                    });
                                                                                                                                                                                    
                                                                                                                                                                                    async function handlePhotoOrder(message, attachment, additionalText) {
                                                                                                                                                                                      const thinking = await message.reply('Analyzing nameplate photo...');
                                                                                                                                                                                      
                                                                                                                                                                                        try {
                                                                                                                                                                                            // Download image and convert to base64
                                                                                                                                                                                                const imageResp = await axios.get(attachment.url, { responseType: 'arraybuffer' });
                                                                                                                                                                                                    const base64 = Buffer.from(imageResp.data).toString('base64');
                                                                                                                                                                                                        const mediaType = attachment.contentType || 'image/jpeg';
                                                                                                                                                                                                        
                                                                                                                                                                                                            // Ask Claude to read the nameplate
                                                                                                                                                                                                                const claudeResp = await anthropic.messages.create({
                                                                                                                                                                                                                      model: 'claude-opus-4-5',
                                                                                                                                                                                                                            max_tokens: 1024,
                                                                                                                                                                                                                                  messages: [{
                                                                                                                                                                                                                                          role: 'user',
                                                                                                                                                                                                                                                  content: [
                                                                                                                                                                                                                                                            {
                                                                                                                                                                                                                                                                        type: 'image',
                                                                                                                                                                                                                                                                                    source: { type: 'base64', media_type: mediaType, data: base64 },
                                                                                                                                                                                                                                                                                              },
                                                                                                                                                                                                                                                                                                        {
                                                                                                                                                                                                                                                                                                                    type: 'text',
                                                                                                                                                                                                                                                                                                                                text: `You are an HVAC equipment nameplate reader. Extract from this nameplate image:
                                                                                                                                                                                                                                                                                                                                - Brand (manufacturer name)
                                                                                                                                                                                                                                                                                                                                - Model number
                                                                                                                                                                                                                                                                                                                                - Serial number
                                                                                                                                                                                                                                                                                                                                - Tonnage/BTU
                                                                                                                                                                                                                                                                                                                                - Voltage
                                                                                                                                                                                                                                                                                                                                - Refrigerant type
                                                                                                                                                                                                                                                                                                                                Return ONLY a JSON object like: {"brand":"Carrier","model":"24ACC636A003","serial":"1234","tonnage":"3 ton","voltage":"208-230/1/60","refrigerant":"R-410A"}
                                                                                                                                                                                                                                                                                                                                If you cannot read a field clearly, use null for that field.`,
                                                                                                                                                                                                                                                                                                                                          },
                                                                                                                                                                                                                                                                                                                                                  ],
                                                                                                                                                                                                                                                                                                                                                        }],
                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                let nameplateData;
                                                                                                                                                                                                                                                                                                                                                                    try {
                                                                                                                                                                                                                                                                                                                                                                          const jsonText = claudeResp.content[0].text.trim();
                                                                                                                                                                                                                                                                                                                                                                                nameplateData = JSON.parse(jsonText.replace(/```json\n?|\n?```/g, ''));
                                                                                                                                                                                                                                                                                                                                                                                    } catch {
                                                                                                                                                                                                                                                                                                                                                                                          await thinking.edit('Could not parse nameplate data. Please try a clearer photo.');
                                                                                                                                                                                                                                                                                                                                                                                                return;
                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                        const brand = nameplateData.brand;
                                                                                                                                                                                                                                                                                                                                                                                                            const vendor = getVendorForBrand(brand);
                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                // Parse part/PO from additional text if provided
                                                                                                                                                                                                                                                                                                                                                                                                                    let part = null;
                                                                                                                                                                                                                                                                                                                                                                                                                        let po = null;
                                                                                                                                                                                                                                                                                                                                                                                                                            let qty = 1;
                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                if (additionalText) {
                                                                                                                                                                                                                                                                                                                                                                                                                                      // Try to parse "part | PO-xxx" or "part qty PO-xxx"
                                                                                                                                                                                                                                                                                                                                                                                                                                            const poMatch = additionalText.match(/PO[-\s]?\d+[-\w]*/i);
                                                                                                                                                                                                                                                                                                                                                                                                                                                  if (poMatch) po = poMatch[0].replace(/\s/g, '-').toUpperCase();
                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                        const qtyMatch = additionalText.match(/\bqty\s*(\d+)\b/i) || additionalText.match(/\b(\d+)\s*(?:units?|pcs?|pieces?)\b/i);
                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (qtyMatch) qty = parseInt(qtyMatch[1]);
                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // Everything else is part description
                                                                                                                                                                                                                                                                                                                                                                                                                                                                          part = additionalText
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  .replace(poMatch ? poMatch[0] : '', '')
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          .replace(qtyMatch ? qtyMatch[0] : '', '')
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  .replace(/[|,]/g, '')
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          .trim() || null;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const order = {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        brand: brand || 'Unknown',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              model: nameplateData.model,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    serial: nameplateData.serial,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          tonnage: nameplateData.tonnage,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                voltage: nameplateData.voltage,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      refrigerant: nameplateData.refrigerant,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            part,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  po,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        qty,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              vendor,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    fromPhoto: true,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            await thinking.delete();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (!part || !po) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      // Ask for missing info
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const embed = new EmbedBuilder()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .setColor(0x0099FF)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            .setTitle('Nameplate Read')
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .addFields(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              { name: 'Brand', value: brand || 'Unknown', inline: true },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        { name: 'Model', value: nameplateData.model || 'N/A', inline: true },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  { name: 'Vendor', value: vendor ? vendor.name : 'Unknown brand — vendor not found', inline: false },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          )
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  .setFooter({ text: 'Reply with: part description | PO-XXXX (qty optional)' });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Store partial order
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const orderId = Date.now().toString();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    pendingOrders.set(orderId, { ...order, awaitingDetails: true });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          await message.reply({ embeds: [embed] });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              } else {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    await sendOrderConfirmation(message, order, false);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          } catch (err) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              console.error('Photo order error:', err);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  await thinking.edit(`Error reading photo: ${err.message}`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    async function handleNaturalTextOrder(message, text) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const thinking = await message.reply('Parsing your order...');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const claudeResp = await anthropic.messages.create({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  model: 'claude-opus-4-5',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        max_tokens: 512,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              messages: [{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      role: 'user',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              content: `Parse this HVAC parts order message and return ONLY a JSON object:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              Message: "${text}"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              Extract: brand, part (description), qty (integer, default 1), po (PO number like PO-2025-0001), model (if mentioned), notes (any extra info).
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              Return JSON only: {"brand":"...","part":"...","qty":1,"po":"...","model":null,"notes":null}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              If a field is missing, use null.`,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            let parsed;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const jsonText = claudeResp.content[0].text.trim();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            parsed = JSON.parse(jsonText.replace(/```json\n?|\n?```/g, ''));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                } catch {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      await thinking.edit('Could not parse order. Try: `Brand Part description qty N PO-XXXX`');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            return;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const vendor = getVendorForBrand(parsed.brand);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const order = { ...parsed, vendor };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            await thinking.delete();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                await sendOrderConfirmation(message, order, false);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  } catch (err) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      console.error('Natural text parse error:', err);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          await thinking.edit(`Error parsing order: ${err.message}`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            async function sendOrderConfirmation(context, order, isSlash) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const orderId = Date.now().toString();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                pendingOrders.set(orderId, order);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const embed = buildEmbed(order, 'pending');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const row = new ActionRowBuilder().addComponents(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        new ButtonBuilder()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              .setCustomId(`confirm:${orderId}`)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .setLabel('Place Call')
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          .setStyle(ButtonStyle.Success)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                .setEmoji(''),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    new ButtonBuilder()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          .setCustomId(`cancel:${orderId}`)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                .setLabel('Cancel')
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      .setStyle(ButtonStyle.Danger)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            .setEmoji(''),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (isSlash) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    await context.reply({ embeds: [embed], components: [row] });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      } else {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          await context.reply({ embeds: [embed], components: [row] });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              // Auto-expire after 5 minutes
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                setTimeout(() => pendingOrders.delete(orderId), 5 * 60 * 1000);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                async function placeOrder(interaction, order) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const calling = new EmbedBuilder()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      .setColor(0xFFA500)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          .setTitle('Placing call...')
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              .setDescription(`Calling ${order.vendor ? order.vendor.name : 'vendor'}...`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                await interaction.editReply({ embeds: [calling], components: [] });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const response = await axios.post(`${BACKEND_URL}/order`, {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            brand: order.brand,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  model: order.model || 'N/A',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        part: order.part,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              qty: order.qty || 1,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    po: order.po,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          vendor: order.vendor,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                notes: order.notes || null,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      companyName: 'Semper Fi Heating and Cooling',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const { callSid } = response.data;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const successEmbed = buildEmbed(order, 'calling', callSid);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      await interaction.editReply({ embeds: [successEmbed] });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // Poll for status
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              await pollCallStatus(callSid, interaction, order);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                } catch (err) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    console.error('Order placement error:', err);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const errorEmbed = buildEmbed(order, 'error', null, err.response?.data?.error || err.message);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            await interaction.editReply({ embeds: [errorEmbed] });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              async function pollCallStatus(callSid, interaction, order) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                let polls = 0;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const interval = setInterval(async () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      polls++;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const { data } = await axios.get(`${BACKEND_URL}/call-status/${callSid}`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      if (['completed', 'failed', 'busy', 'no-answer', 'cancelled'].includes(data.status) || polls >= 15) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              clearInterval(interval);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const finalStatus = data.status === 'completed' ? 'completed' : 'error';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const finalEmbed = buildEmbed(order, finalStatus, callSid,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        finalStatus === 'error' ? `Call ended: ${data.status}` : null);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                await interaction.editReply({ embeds: [finalEmbed] });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          } catch { clearInterval(interval); }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }, 4000);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            function buildEmbed(order, status, callSid = null, error = null) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const colors = {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  pending:   0x0099FF,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      calling:   0xFFA500,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          placed:    0x00CC44,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              completed: 0x1D9E75,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  cancelled: 0x888780,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      error:     0xE24B4A,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const statusLabels = {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              pending:   'Awaiting confirmation',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  calling:   'Placing call...',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      placed:    'Call placed',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          completed: 'Call completed',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              cancelled: 'Cancelled',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  error:     'Error',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const embed = new EmbedBuilder()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          .setColor(colors[status] || 0x378ADD)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              .setTitle('Semper Fi - Parts Order')
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  .setDescription(statusLabels[status] || status)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      .addFields(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            { name: 'Vendor', value: order.vendor ? `${order.vendor.name} - ${order.vendor.city || ''}${order.vendor.phone}\n${order.vendor.address}` : 'Unknown', inline: true },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  { name: 'Brand', value: order.brand || '-', inline: true },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        { name: '\u200b', value: '\u200b', inline: true },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              { name: 'Part', value: order.part || '-', inline: true },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    { name: 'Qty', value: String(order.qty || 1), inline: true },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          { name: 'Model', value: order.model || '-', inline: true },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                { name: 'PO Number', value: order.po || '-', inline: true },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    )
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        .setFooter({ text: 'Semper Fi Heating & Cooling' })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            .setTimestamp();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (order.notes) embed.addFields({ name: 'Notes', value: order.notes });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (callSid) embed.addFields({ name: 'Call SID', value: `\`${callSid}\`` });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  if (error) embed.addFields({ name: 'Error', value: error });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return embed;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    client.login(process.env.DISCORD_TOKEN);
